const items = $input.all();
const now = new Date();
const currentMonth = now.getMonth();
const currentYear = now.getFullYear();

const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const monthName = monthNames[currentMonth];
// Production mode - summarizes previous month:
let targetMonth = currentMonth - 1;
let targetYear = currentYear;
if (targetMonth < 0) {
  targetMonth = 11;
  targetYear = currentYear - 1;
}


const expenses = items
  .filter(i => i.json.CATEGORY !== undefined && i.json.CATEGORY !== 'CATEGORY')
  .filter(e => {
    const d = new Date(e.json.DATE);
    return d.getMonth() === targetMonth && d.getFullYear() === targetYear;
  });

const gainz = items
  .filter(i => i.json.SOURCE !== undefined && i.json.SOURCE !== 'SOURCE')
  .filter(g => {
    const d = new Date(g.json.DATE);
    return d.getMonth() === targetMonth && d.getFullYear() === targetYear;
  });

const totalExpenses = expenses.reduce((sum, e) => sum + Number(e.json.AMOUNT || 0), 0);
const totalGainz = gainz.reduce((sum, g) => sum + Number(g.json.AMOUNT || 0), 0);
const balance = totalGainz - totalExpenses;
const balanceSign = balance >= 0 ? '+' : '';
const balanceClass = balance >= 0 ? 'green' : 'red';
const balanceEmoji = balance >= 0 ? '✅' : '⚠️';
const txCount = expenses.length + gainz.length;

const categories = {};
expenses.forEach(e => {
  const cat = e.json.CATEGORY || 'Other';
  categories[cat] = (categories[cat] || 0) + Number(e.json.AMOUNT || 0);
});

const sortedCats = Object.entries(categories).sort((a, b) => b[1] - a[1]);
const topCategory = sortedCats.length > 0 ? sortedCats[0] : null;

// Category table rows
const catRows = sortedCats.length > 0
  ? sortedCats.map(([cat, amt]) =>
      `<tr><td style="padding:6px 12px;font-size:14px;border-bottom:1px solid #f0f0f0">${cat}</td><td style="padding:6px 12px;font-size:14px;border-bottom:1px solid #f0f0f0;text-align:right;font-weight:600;color:#333">P${Number(amt).toLocaleString()}</td></tr>`
    ).join('\n')
  : '<tr><td colspan="2" style="padding:6px 12px;text-align:center">No expenses this month</td></tr>';

const topBadge = topCategory
  ? `<div style="text-align:center;margin-top:14px;padding:8px 16px;background:#e8f5e9;border-radius:20px;font-size:13px;color:#1b8a3d">🏆 Top: <strong>${topCategory[0]}</strong> (P${Number(topCategory[1]).toLocaleString()})</div>`
  : '';

const emailBody = `<!DOCTYPE html>
<html>
<head>
  <style>
    body { margin: 0; padding: 0; background: #f0f2f5; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; }
    .container { max-width: 480px; margin: 20px auto; background: white; border-radius: 16px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
    .header { background: #1a73e8; padding: 24px; text-align: center; }
    .header h1 { margin: 0; color: white; font-size: 22px; letter-spacing: 2px; }
    .header p { margin: 6px 0 0; color: rgba(255,255,255,0.85); font-size: 14px; }
    .body { padding: 20px 24px; }
    .section-title { font-size: 13px; font-weight: 700; color: #1a73e8; text-transform: uppercase; letter-spacing: 1px; margin: 20px 0 12px; }
    .footer { text-align: center; padding: 16px 24px 20px; color: #888; font-size: 12px; border-top: 1px solid #e8eaed; }
    .green { color: #1b8a3d; font-weight: 700; }
    .red { color: #c5221f; font-weight: 700; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>SALAPI</h1>
      <p>Monthly Summary — ${monthName} ${targetYear}</p>
    </div>
    <div class="body">
      <table style="width:100%;background:#f8f9fa;border-radius:12px;border-collapse:collapse;margin-bottom:16px">
        <tr>
          <td style="padding:12px 16px 8px;font-size:14px;color:#5f6368">📈 Income</td>
          <td style="padding:12px 16px 8px;text-align:right"><span class="green">+P${totalGainz.toLocaleString()}</span> <span style="color:#5f6368;font-size:13px">(${gainz.length})</span></td>
        </tr>
        <tr>
          <td style="padding:8px 16px;font-size:14px;color:#5f6368">📉 Expenses</td>
          <td style="padding:8px 16px;text-align:right"><span class="red">-P${totalExpenses.toLocaleString()}</span> <span style="color:#5f6368;font-size:13px">(${expenses.length})</span></td>
        </tr>
        <tr>
          <td style="padding:12px 16px 12px;font-size:15px;font-weight:700;color:#1a73e8;border-top:2px solid #1a73e8">💰 Balance</td>
          <td style="padding:12px 16px 12px;text-align:right;font-size:16px;font-weight:700;border-top:2px solid #1a73e8" class="${balanceClass}">${balanceEmoji} ${balanceSign}P${Math.abs(balance).toLocaleString()}</td>
        </tr>
      </table>

      <div class="section-title">🏷️ Categories</div>
      <table style="width:100%;background:#f8f9fa;border-radius:12px;border-collapse:collapse;margin-bottom:4px">
${catRows}
      </table>

      ${topBadge}

      <p style="text-align:center;margin:14px 0 0;font-size:13px;color:#5f6368">${txCount} total transactions</p>
    </div>
    <div class="footer">
      Stay on top of your finances, one text at a time.<br>
      — Salapi Finance Bot
    </div>
  </div>
</body>
</html>`;

const subject = 'Salapi Summary - ' + monthName + ' ' + targetYear;

return [{ json: { emailBody, subject } }];
